import React, { useState, useRef } from 'react';
import { analyzeEmission, generateOptimization } from '../services/api';
import OptimizationScanner from '../components/OptimizationScanner';
import ComparisonTable from '../components/ComparisonTable';

function ResNetAnalysisPage({ onNavigateBack }) {
    // --- Merged State ---
    const [step, setStep] = useState('IDLE'); // IDLE (Upload), SCANNING_IMAGE, SHOW_BASELINE, ANALYZING, SHOW_SUGGESTIONS, OPTIMIZING, COMPLETED
    const [selectedImage, setSelectedImage] = useState(null);
    const [scanProgress, setScanProgress] = useState(0);
    const fileInputRef = useRef(null);
    const audioContextRef = useRef(null);
    const scanSoundIntervalRef = useRef(null);

    // Metrics State
    const [baselineMetrics, setBaselineMetrics] = useState(null);
    const [analysisResult, setAnalysisResult] = useState(null);
    const [optimizationPlan, setOptimizationPlan] = useState(null);
    const [optimizedMetrics, setOptimizedMetrics] = useState(null);

    // --- Robotic Scanning Sound Effects ---
    const playScanSound = () => {
        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)();
        }
        const ctx = audioContextRef.current;

        // Create oscillator for electronic beep
        const osc = ctx.createOscillator();
        const gainNode = ctx.createGain();

        osc.connect(gainNode);
        gainNode.connect(ctx.destination);

        // Random frequency for variety (scanning effect)
        const baseFreq = 800 + Math.random() * 400;
        osc.frequency.setValueAtTime(baseFreq, ctx.currentTime);
        osc.frequency.exponentialRampToValueAtTime(baseFreq * 0.5, ctx.currentTime + 0.15);

        osc.type = 'sine';
        gainNode.gain.setValueAtTime(0.1, ctx.currentTime);
        gainNode.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.15);

        osc.start(ctx.currentTime);
        osc.stop(ctx.currentTime + 0.15);
    };

    const playLayerFlipSound = () => {
        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)();
        }
        const ctx = audioContextRef.current;

        // Swoosh/flip sound
        const osc = ctx.createOscillator();
        const gainNode = ctx.createGain();
        const filter = ctx.createBiquadFilter();

        osc.connect(filter);
        filter.connect(gainNode);
        gainNode.connect(ctx.destination);

        filter.type = 'lowpass';
        filter.frequency.setValueAtTime(2000, ctx.currentTime);
        filter.frequency.exponentialRampToValueAtTime(200, ctx.currentTime + 0.3);

        osc.frequency.setValueAtTime(600, ctx.currentTime);
        osc.frequency.exponentialRampToValueAtTime(100, ctx.currentTime + 0.3);
        osc.type = 'sawtooth';

        gainNode.gain.setValueAtTime(0.08, ctx.currentTime);
        gainNode.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.3);

        osc.start(ctx.currentTime);
        osc.stop(ctx.currentTime + 0.3);
    };

    const startScanSounds = () => {
        // Play sounds periodically during scan
        playScanSound();
        let soundCounter = 0;
        scanSoundIntervalRef.current = setInterval(() => {
            soundCounter++;
            if (soundCounter % 3 === 0) {
                playLayerFlipSound(); // Layer flip swoosh every 3rd sound
            } else {
                playScanSound(); // Regular scan beep
            }
        }, 200);
    };

    const stopScanSounds = () => {
        if (scanSoundIntervalRef.current) {
            clearInterval(scanSoundIntervalRef.current);
            scanSoundIntervalRef.current = null;
        }
    };

    // --- Image Handling (Restored) ---
    const handleImageUpload = (e) => {
        if (e.target.files && e.target.files[0]) {
            const file = e.target.files[0];
            const reader = new FileReader();
            reader.onload = (ev) => {
                setSelectedImage({
                    src: ev.target.result,
                    size: file.size, // bytes
                    name: file.name
                });
                setStep('READY_TO_SCAN');
            };
            reader.readAsDataURL(file);
        }
    };

    const startImageScan = () => {
        setStep('SCANNING_IMAGE');
        setScanProgress(0);

        // Robotic Voice
        const utterance = new SpeechSynthesisUtterance("Initiating ResNet-18 Neural Scan. Measuring Baseline Emissions.");
        utterance.rate = 1.0;
        utterance.pitch = 0.8;
        window.speechSynthesis.speak(utterance);

        // Start scanning sounds
        startScanSounds();

        let progress = 0;
        const interval = setInterval(() => {
            progress += 2;
            setScanProgress(progress);

            if (progress >= 100) {
                clearInterval(interval);
                stopScanSounds();
                calculateBaselineEmission();
            }
        }, 50);
    };

    const calculateBaselineEmission = () => {
        // Logic from previous version to generate baseline
        const pixels = selectedImage ? selectedImage.size : 500000;
        const complexityFactor = 18;
        const energyPerBit = 0.00000015;
        const totalEnergyJ = (pixels * 8) * complexityFactor * energyPerBit;
        const carbonIntensity = 475;
        const energyKWh = totalEnergyJ / 3600000;
        const carbonG = energyKWh * carbonIntensity; // grams
        const carbonKg = carbonG / 1000;

        const metrics = {
            model: "ResNet-18",
            runtime_minutes: 30, // Simulated training time
            co2_kg: parseFloat(carbonKg.toFixed(6)) || 0.4500, // Fallback if too small
            power_usage_w: 250,
            energy_kwh: parseFloat(energyKWh.toFixed(6)) || 0.1500,
            epochs: 10,
            batch_size: 64,
            gpu_load: 95
        };

        setBaselineMetrics(metrics);
        setStep('SHOW_BASELINE');
    };

    // --- Optimization Workflow (New) ---
    const startAnalysis = async () => {
        setStep('ANALYZING');
        setScanProgress(0);

        // Animate Scanner
        let progress = 0;
        const interval = setInterval(() => {
            progress += 5;
            setScanProgress(progress);
            if (progress >= 100) clearInterval(interval);
        }, 100);

        // Fetch Analysis Backend
        try {
            const analysis = await analyzeEmission(baselineMetrics);
            const plan = await generateOptimization(baselineMetrics);

            setTimeout(() => {
                setAnalysisResult(analysis.data);
                setOptimizationPlan(plan.data);
                setStep('SHOW_SUGGESTIONS');
            }, 2500);
        } catch (error) {
            console.error("Analysis Failed", error);
            // Fallback for demo if backend fails
            setTimeout(() => {
                // Mock fallback
                setAnalysisResult({
                    factors: ["High GPU Load Detected", "Batch Size > 32"]
                });
                setOptimizationPlan({
                    suggestions: ["Reduce Batch Size to 32", "Enable Mixed Precision"],
                    estimated_reduction_percentage: 45,
                    optimized_config: { epochs: 5, batch_size: 32 }
                });
                setStep('SHOW_SUGGESTIONS');
            }, 2500);
        }
    };

    const applyOptimization = () => {
        setStep('OPTIMIZING');
        setScanProgress(0);

        let progress = 0;
        const interval = setInterval(() => {
            progress += 2;
            setScanProgress(progress);
            if (progress >= 100) clearInterval(interval);
        }, 50);

        setTimeout(() => {
            setOptimizedMetrics({
                ...baselineMetrics,
                runtime_minutes: 15,
                co2_kg: (baselineMetrics.co2_kg * 0.55).toFixed(4),
                energy_kwh: (baselineMetrics.energy_kwh * 0.55).toFixed(4),
                epochs: optimizationPlan?.optimized_config?.epochs || 5,
                batch_size: optimizationPlan?.optimized_config?.batch_size || 32
            });
            setStep('COMPLETED');
        }, 4000);
    };

    return (
        <div style={{ background: 'var(--bg-primary)', minHeight: '100vh', padding: '40px', position: 'relative', overflowX: 'hidden' }}>
            <div className="scanline"></div>

            {/* Header */}
            <header style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '40px' }}>
                <button
                    onClick={onNavigateBack}
                    className="robotic-btn"
                    style={{
                        padding: '10px 20px',
                        background: 'rgba(0, 210, 255, 0.1)',
                        border: '1px solid var(--robotic-blue)',
                        color: '#fff',
                        cursor: 'pointer'
                    }}
                >
                    [ BACK_TO_HQ ]
                </button>
                <div style={{ color: 'var(--robotic-blue)', letterSpacing: '2px', fontWeight: 'bold' }}>
                    MODULE: ResNet-18_CNN_DIAGNOSTICS
                </div>
            </header>

            {/* --- STEP 1: IMAGE UPLOAD & SCANNING --- */}
            {step === 'IDLE' || step === 'READY_TO_SCAN' || step === 'SCANNING_IMAGE' ? (
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(350px, 1fr))', gap: '40px' }}>

                    {/* Left: Input */}
                    <div>
                        <h3 style={{ fontSize: '1.2rem', marginBottom: '20px', color: '#fff' }}>[ 01 ] IMAGE_INPUT_BUFFER</h3>
                        <div className="glass-card" style={{ height: '400px', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', border: '2px dashed rgba(0, 210, 255, 0.3)', position: 'relative', overflow: 'hidden', perspective: '1000px' }}>
                            {!selectedImage ? (
                                <>
                                    <input type="file" accept="image/*" ref={fileInputRef} style={{ display: 'none' }} onChange={handleImageUpload} />
                                    <button
                                        onClick={() => fileInputRef.current.click()}
                                        className="robotic-btn"
                                        style={{ padding: '20px 40px', background: 'var(--accent-blue)', border: 'none', color: '#000', borderRadius: '4px', cursor: 'pointer', fontWeight: 'bold' }}
                                    >
                                        + UPLOAD_SOURCE_IMG
                                    </button>
                                </>
                            ) : (
                                <>
                                    {/* Layer Flip Container */}
                                    <div style={{ position: 'relative', width: '100%', height: '100%', transformStyle: 'preserve-3d' }}>
                                        {/* Original Image (Base Layer) */}
                                        <img
                                            src={selectedImage.src}
                                            alt="Target"
                                            style={{
                                                width: '100%',
                                                height: '100%',
                                                objectFit: 'contain',
                                                opacity: step === 'SCANNING_IMAGE' ? 0.3 : 1,
                                                filter: step === 'SCANNING_IMAGE' ? 'grayscale(50%)' : 'none',
                                                transition: 'all 0.5s ease'
                                            }}
                                        />

                                        {/* Animated Flipping Layers During Scan */}
                                        {step === 'SCANNING_IMAGE' && (
                                            <>
                                                {/* Layer 1 - CONV2D (Red Channel) */}
                                                <div style={{
                                                    position: 'absolute', top: '10%', left: '10%', width: '80%', height: '80%',
                                                    background: `url(${selectedImage.src})`, backgroundSize: 'cover', backgroundPosition: 'center',
                                                    filter: 'sepia(100%) hue-rotate(-50deg) saturate(300%)',
                                                    opacity: 0.7,
                                                    border: '2px solid rgba(255, 100, 100, 0.5)',
                                                    animation: 'flipLayer1 2s ease-in-out infinite',
                                                    transformOrigin: 'center left',
                                                    boxShadow: '0 0 20px rgba(255, 100, 100, 0.3)'
                                                }}></div>

                                                {/* Layer 2 - BATCH_NORM (Green Channel) */}
                                                <div style={{
                                                    position: 'absolute', top: '15%', left: '15%', width: '70%', height: '70%',
                                                    background: `url(${selectedImage.src})`, backgroundSize: 'cover', backgroundPosition: 'center',
                                                    filter: 'sepia(100%) hue-rotate(50deg) saturate(200%)',
                                                    opacity: 0.6,
                                                    border: '2px solid rgba(100, 255, 100, 0.5)',
                                                    animation: 'flipLayer2 2.5s ease-in-out infinite',
                                                    transformOrigin: 'center right',
                                                    boxShadow: '0 0 20px rgba(100, 255, 100, 0.3)'
                                                }}></div>

                                                {/* Layer 3 - RELU (Blue Channel) */}
                                                <div style={{
                                                    position: 'absolute', top: '20%', left: '20%', width: '60%', height: '60%',
                                                    background: `url(${selectedImage.src})`, backgroundSize: 'cover', backgroundPosition: 'center',
                                                    filter: 'sepia(100%) hue-rotate(180deg) saturate(400%)',
                                                    opacity: 0.5,
                                                    border: '2px solid rgba(100, 150, 255, 0.5)',
                                                    animation: 'flipLayer3 3s ease-in-out infinite',
                                                    transformOrigin: 'top center',
                                                    boxShadow: '0 0 20px rgba(100, 150, 255, 0.3)'
                                                }}></div>

                                                {/* Layer 4 - MAXPOOL (Cyan Feature Map) */}
                                                <div style={{
                                                    position: 'absolute', top: '25%', left: '25%', width: '50%', height: '50%',
                                                    background: `url(${selectedImage.src})`, backgroundSize: 'cover', backgroundPosition: 'center',
                                                    filter: 'grayscale(100%) brightness(1.5) contrast(200%)',
                                                    opacity: 0.8,
                                                    border: '2px solid var(--robotic-blue)',
                                                    animation: 'flipLayer4 1.5s ease-in-out infinite',
                                                    transformOrigin: 'bottom center',
                                                    boxShadow: '0 0 30px var(--robotic-blue)'
                                                }}></div>

                                                {/* Scanline moving across */}
                                                <div style={{
                                                    position: 'absolute', top: 0, left: 0, width: '100%', height: '4px',
                                                    background: 'var(--accent-green)',
                                                    boxShadow: '0 0 30px var(--accent-green)',
                                                    animation: 'scanImage 2s linear infinite'
                                                }}></div>

                                                {/* Processing overlay text */}
                                                <div style={{
                                                    position: 'absolute', bottom: '10px', left: '10px', right: '10px',
                                                    background: 'rgba(0,0,0,0.8)', padding: '8px 15px', borderRadius: '4px',
                                                    color: 'var(--accent-green)', fontSize: '0.8rem', fontFamily: 'monospace',
                                                    border: '1px solid var(--accent-green)'
                                                }}>
                                                    LAYER DECOMPOSITION: {scanProgress}% | CONV2D → BATCH_NORM → RELU → MAXPOOL
                                                </div>
                                            </>
                                        )}
                                    </div>

                                    {step === 'READY_TO_SCAN' && (
                                        <div style={{ position: 'absolute', bottom: '20px' }}>
                                            <button onClick={startImageScan} className="robotic-btn" style={{ padding: '15px 30px', background: 'rgba(0,0,0,0.8)', border: '1px solid var(--accent-green)', color: 'var(--accent-green)', fontWeight: 900, cursor: 'pointer' }}>
                                                INITIALIZE_SCAN
                                            </button>
                                        </div>
                                    )}
                                </>
                            )}
                        </div>
                    </div>

                    {/* Right: Log */}
                    <div>
                        <h3 style={{ fontSize: '1.2rem', marginBottom: '20px', color: '#fff' }}>[ 02 ] NEURAL_PROCESS_LOG</h3>
                        <div className="glass-card" style={{ height: '400px', padding: '20px', fontFamily: 'monospace', overflowY: 'auto' }}>
                            {step === 'SCANNING_IMAGE' && (
                                <div style={{ color: 'var(--accent-blue)' }}>
                                    <p style={{ color: scanProgress > 10 ? 'var(--success-green)' : 'var(--accent-blue)' }}>{'>'} LAYER_01 [CONV2D_3x3] ... {scanProgress > 10 ? 'EXTRACTED ✓' : 'PROCESSING...'}</p>
                                    <p style={{ color: scanProgress > 30 ? 'var(--success-green)' : 'var(--accent-blue)' }}>{'>'} LAYER_02 [BATCH_NORM] ... {scanProgress > 30 ? 'NORMALIZED ✓' : scanProgress > 10 ? 'PROCESSING...' : 'PENDING'}</p>
                                    <p style={{ color: scanProgress > 50 ? 'var(--success-green)' : 'var(--accent-blue)' }}>{'>'} LAYER_03 [RELU_ACTIVATION] ... {scanProgress > 50 ? 'ACTIVATED ✓' : scanProgress > 30 ? 'PROCESSING...' : 'PENDING'}</p>
                                    <p style={{ color: scanProgress > 70 ? 'var(--success-green)' : 'var(--accent-blue)' }}>{'>'} LAYER_04 [MAXPOOL_2x2] ... {scanProgress > 70 ? 'POOLED ✓' : scanProgress > 50 ? 'PROCESSING...' : 'PENDING'}</p>
                                    <p style={{ color: scanProgress > 85 ? 'var(--success-green)' : 'var(--accent-blue)' }}>{'>'} LAYER_05 [FEATURE_MAP] ... {scanProgress > 85 ? 'GENERATED ✓' : scanProgress > 70 ? 'PROCESSING...' : 'PENDING'}</p>
                                    <p style={{ marginTop: '20px', color: 'var(--accent-orange)' }}>{'>'} CARBON FOOTPRINT CALCULATION: {scanProgress}%</p>
                                    <div style={{ width: '100%', height: '6px', background: 'rgba(255,255,255,0.1)', marginTop: '10px', borderRadius: '3px' }}>
                                        <div style={{ width: `${scanProgress}%`, height: '100%', background: 'var(--primary-gradient)', borderRadius: '3px', transition: 'width 0.1s' }}></div>
                                    </div>
                                    {scanProgress > 90 && (
                                        <p style={{ marginTop: '20px', color: 'var(--accent-magenta)', animation: 'pulse 1s infinite' }}>{'>'} SYNTHESIZING EMISSION DATA...</p>
                                    )}
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            ) : null}

            {/* --- STEP 2: BASELINE RESULTS & OPTIMIZATION ENTRY --- */}
            {(step === 'SHOW_BASELINE' || step === 'SHOW_SUGGESTIONS' || step === 'COMPLETED') && baselineMetrics && (
                <div className="glass-card fade-in" style={{ padding: '30px', marginBottom: '40px', borderLeft: '4px solid var(--accent-magenta)' }}>
                    <h3 style={{ color: '#fff', marginBottom: '20px' }}>📊 BASELINE EMISSION DETECTED</h3>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '20px', textAlign: 'center' }}>
                        <div>
                            <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>CO₂ Magnitude</div>
                            <div style={{ fontSize: '2rem', fontWeight: 'bold', color: 'var(--accent-magenta)' }}>{baselineMetrics.co2_kg} kg</div>
                        </div>
                        <div>
                            <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>Energy Used</div>
                            <div style={{ fontSize: '2rem', fontWeight: 'bold', color: '#fff' }}>{baselineMetrics.energy_kwh} kWh</div>
                        </div>
                        <div>
                            <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>Batch Size</div>
                            <div style={{ fontSize: '2rem', fontWeight: 'bold', color: '#fff' }}>{baselineMetrics.batch_size}</div>
                        </div>
                        <div>
                            <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>Epochs</div>
                            <div style={{ fontSize: '2rem', fontWeight: 'bold', color: '#fff' }}>{baselineMetrics.epochs}</div>
                        </div>
                    </div>

                    {step === 'SHOW_BASELINE' && (
                        <div style={{ textAlign: 'center', marginTop: '40px' }}>
                            <p style={{ color: 'var(--text-secondary)', marginBottom: '20px' }}>
                                High emissions detected based on current model parameters.
                            </p>
                            <button
                                onClick={startAnalysis}
                                className="robotic-btn"
                                style={{
                                    padding: '15px 40px',
                                    fontSize: '1.2rem',
                                    border: '2px solid var(--robotic-blue)',
                                    background: 'transparent',
                                    color: 'var(--robotic-blue)',
                                    cursor: 'pointer',
                                    boxShadow: '0 0 15px rgba(0,210,255,0.2)'
                                }}
                            >
                                [ ANALYZE & IDENTIFY ISSUES ]
                            </button>
                        </div>
                    )}
                </div>
            )}

            {/* --- STEP 3: SCANNER OVERLAY --- */}
            {(step === 'ANALYZING' || step === 'OPTIMIZING') && (
                <OptimizationScanner currentStep={step} progress={scanProgress} />
            )}

            {/* --- STEP 4: ANALYSIS & SUGGESTIONS --- */}
            {(step === 'SHOW_SUGGESTIONS' || step === 'COMPLETED') && analysisResult && optimizationPlan && (
                <div className="fade-in">
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '40px', marginBottom: '40px' }}>
                        <div className="glass-card" style={{ padding: '30px', borderTop: '4px solid var(--warning-yellow)' }}>
                            <h3 style={{ color: 'var(--accent-orange)' }}>🧠 IMPACT ANALYSIS</h3>
                            <ul style={{ listStyle: 'none', padding: 0, marginTop: '20px' }}>
                                {analysisResult.factors.map((factor, i) => (
                                    <li key={i} style={{ marginBottom: '15px', color: '#ffd700' }}>⚠ {factor}</li>
                                ))}
                            </ul>
                        </div>
                        <div className="glass-card" style={{ padding: '30px', borderTop: '4px solid var(--success-green)' }}>
                            <h3 style={{ color: 'var(--success-green)' }}>💡 SUGGESTED OPTIMIZATIONS</h3>
                            <ul style={{ listStyle: 'none', padding: 0, marginTop: '20px' }}>
                                {optimizationPlan.suggestions.map((suggestion, i) => (
                                    <li key={i} style={{ marginBottom: '15px', color: '#fff' }}>✓ {suggestion}</li>
                                ))}
                            </ul>
                        </div>
                    </div>

                    {step === 'SHOW_SUGGESTIONS' && (
                        <div style={{ textAlign: 'center' }}>
                            <button
                                onClick={applyOptimization}
                                className="robotic-btn"
                                style={{
                                    padding: '20px 50px',
                                    fontSize: '1.3rem',
                                    background: 'var(--primary-gradient)',
                                    border: 'none',
                                    color: '#000',
                                    fontWeight: 'bold',
                                    cursor: 'pointer',
                                    boxShadow: '0 0 30px rgba(0,242,254,0.4)',
                                    animation: 'pulse 2s infinite'
                                }}
                            >
                                APPLY OPTIMIZATIONS & RE-RUN
                            </button>
                        </div>
                    )}
                </div>
            )}

            {/* --- STEP 5: FINAL COMPARISON --- */}
            {step === 'COMPLETED' && optimizedMetrics && (
                <div className="fade-in">
                    <div className="glass-card" style={{ padding: '20px', marginBottom: '40px', background: 'rgba(0, 255, 127, 0.05)', border: '1px solid var(--success-green)' }}>
                        <h2 style={{ color: '#fff' }}>✅ OPTIMIZATION SUCCESSFUL</h2>
                        <p style={{ color: 'var(--text-secondary)' }}>Model re-calibrated with sustainable parameters.</p>
                    </div>

                    <ComparisonTable baseline={baselineMetrics} optimized={optimizedMetrics} />

                    <div style={{ textAlign: 'center', marginTop: '60px' }}>
                        <button onClick={() => window.location.reload()} className="robotic-btn" style={{ padding: '15px 30px', background: 'transparent', border: '1px solid var(--text-muted)', color: 'var(--text-muted)', cursor: 'pointer' }}>
                            [ START_NEW_SESSION ]
                        </button>
                    </div>
                </div>
            )}

            <style>{`
                @keyframes scanImage {
                    0% { top: 0%; }
                    100% { top: 100%; }
                }
                @keyframes flipLayer1 {
                    0% { transform: rotateY(0deg) translateZ(0px); }
                    50% { transform: rotateY(25deg) translateZ(30px); }
                    100% { transform: rotateY(0deg) translateZ(0px); }
                }
                @keyframes flipLayer2 {
                    0% { transform: rotateY(0deg) translateZ(0px); }
                    50% { transform: rotateY(-25deg) translateZ(40px); }
                    100% { transform: rotateY(0deg) translateZ(0px); }
                }
                @keyframes flipLayer3 {
                    0% { transform: rotateX(0deg) translateZ(0px); }
                    50% { transform: rotateX(20deg) translateZ(50px); }
                    100% { transform: rotateX(0deg) translateZ(0px); }
                }
                @keyframes flipLayer4 {
                    0% { transform: rotateX(0deg) scale(1); }
                    50% { transform: rotateX(-15deg) scale(1.05); }
                    100% { transform: rotateX(0deg) scale(1); }
                }
            `}</style>
        </div>
    );
}

export default ResNetAnalysisPage;
